## CVXPY SOURCE: reductions/eliminate_pwl/canonicalizers/norm1_canon.py
## norm1(x, axis) = sum(abs(x), axis)


norm1_canon <- function(expr, args, solver_context = NULL) {
  x <- args[[1L]]
  axis <- expr@axis
  abs_expr <- Abs(x)
  abs_result <- abs_canon(abs_expr, abs_expr@args)
  abs_x <- abs_result[[1L]]
  constraints <- abs_result[[2L]]
  list(SumEntries(abs_x, axis = axis), constraints)
}

method(dcp_canonicalize, Norm1) <- norm1_canon
method(has_dcp_canon, Norm1) <- function(expr) TRUE
